function solve(nums: number[]): number {
    const n: number = nums.length;
    const visited: boolean[] = new Array(n).fill(false);
    const queue: number[] = [0];
    const steps: number[] = new Array(n).fill(0);
    const isPrime: boolean[] = new Array(1000001).fill(true);
    isPrime[0] = isPrime[1] = false;

    for (let i = 2; i <= 1000000; i++) {
        if (isPrime[i]) {
            for (let j = i * i; j <= 1000000; j += i) {
                isPrime[j] = false;
            }
        }
    }

    const primeFactors: Map<number, number[]> = new Map();

    for (let i = 0; i < n; i++) {
        const num: number = nums[i];
        if (isPrime[num]) {
            primeFactors.set(num, []);
        } else {
            const factors: number[] = [];
            for (let j = 2; j <= Math.sqrt(num); j++) {
                if (num % j === 0) {
                    factors.push(j);
                }
            }
            if (factors.length === 0) {
                factors.push(num);
            }
            primeFactors.set(num, factors);
        }
    }

    let stepsTaken: number = 0;

    while (queue.length > 0) {
        const levelSize: number = queue.length;
        stepsTaken++;

        for (let i = 0; i < levelSize; i++) {
            const current: number = queue.shift() as number;

            if (current === n - 1) {
                return stepsTaken - 1;
            }

            // Move to adjacent cells
            if (current > 0 && !visited[current - 1]) {
                visited[current - 1] = true;
                queue.push(current - 1);
            }
            if (current < n - 1 && !visited[current + 1]) {
                visited[current + 1] = true;
                queue.push(current + 1);
            }

            // Prime teleportation
            if (isPrime[nums[current]]) {
                const prime: number = nums[current];
                const factors: number[] = primeFactors.get(prime) || [];
                for (const factor of factors) {
                    for (let j = 0; j < n; j++) {
                        if (nums[j] % factor === 0 && j !== current && !visited[j]) {
                            visited[j] = true;
                            queue.push(j);
                        }
                    }
                }
            }
        }
    }

    return -1;
}

